package bead

import "time"

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Status    string    `json:"status"`
	Priority  int       `json:"priority"`
	IssueType string    `json:"issue_type"`
	Owner     string    `json:"owner,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	CreatedBy string    `json:"created_by,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
	Type        string `json:"type"` // "blocks", "related", etc.
	CreatedAt   string `json:"created_at,omitempty"`
	CreatedBy   string `json:"created_by,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

// BeadEvent records append-only execution evidence.
type BeadEvent struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Actor     string    `json:"actor,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	Source    string    `json:"source,omitempty"`
}

// Status constants
const (
	StatusOpen       = "open"
	StatusInProgress = "in_progress"
	StatusClosed     = "closed"
	// StatusBlocked marks a bead that is not eligible for agent dispatch —
	// either decomposed into child beads by the triage gate or parked for
	// human intervention after a triage-overflow event. Blocked beads are
	// excluded from ReadyExecution and will not be auto-dispatched.
	StatusBlocked = "blocked"
)

// Default values
const (
	DefaultType     = "task"
	DefaultStatus   = StatusOpen
	DefaultPriority = 2
	DefaultPrefix   = "bx" // used only when repo name detection fails
	MinPriority     = 0
	MaxPriority     = 4
)

// StatusCounts holds aggregate counts for a bead store.
type StatusCounts struct {
	Open    int `json:"open"`
	Closed  int `json:"closed"`
	Blocked int `json:"blocked"`
	Ready   int `json:"ready"`
	Total   int `json:"total"`
}

// Blocker kinds surfaced through BlockedAll. These strings are part of the
// external DDx contract (HELIX reads them to decide how to handle a blocker).
const (
	BlockerKindDependency    = "dependency"
	BlockerKindRetryCooldown = "retry-cooldown"
)

// Blocker describes why an open bead is currently not runnable. Either
// unclosed dependencies exist, or an execute-loop cooldown has parked the
// bead until NextEligibleAt.
type Blocker struct {
	Kind           string   `json:"kind"`
	NextEligibleAt string   `json:"next_eligible_at,omitempty"`
	UnclosedDepIDs []string `json:"unclosed_dep_ids,omitempty"`
	LastStatus     string   `json:"last_status,omitempty"`

1	// Package bead implements the on-disk bead tracker.
2	//
3	// Size envelope (ddx-f8a11202):
4	//
5	// Individual bead fields — description, acceptance, notes, and each event's
6	// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
7	// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
8	// through `bd import`. Writers exceeding the cap are truncated with a
9	// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
10	// preserve the full payload (notably reviewer streams) should persist to a
11	// sidecar artifact under `.ddx/executions/<id>/` and record a path
12	// reference in the event body.
13	//
14	// On the read side, scanners use a 16MB buffer — real-world incidents have
15	// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
16	// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
17	// matches the scanner in the agent package.
18	package bead
19	
20	import (
21		"bufio"
22		"bytes"
23		"context"
24		"crypto/rand"
25		"encoding/hex"
26		"encoding/json"
27		"fmt"
28		"os"
29		"path/filepath"
30		"sort"
31		"strconv"
32		"strings"
33		"time"
34	
35		"github.com/DocumentDrivenDX/ddx/internal/config"
36		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
37	)
38	
39	// Store manages beads via a pluggable backend.
40	type Store struct {
41		Collection string
42		Dir        string
43		File       string
44		Prefix     string
45		LockDir    string
46		LockWait   time.Duration
47		backend    Backend // nil means use built-in JSONL
48	}
49	
50	type StoreOption func(*Store)
51	
52	// WithCollection selects the logical bead collection. The default collection
53	// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
54	func WithCollection(name string) StoreOption {
55		return func(s *Store) {
56			if cleaned := normalizeCollection(name); cleaned != "" {
57				s.Collection = cleaned
58			}
59		}
60	}
61	
62	// NewStore creates a store with the given directory.
63	// Defaults can be overridden via options or environment.
64	func NewStore(dir string, opts ...StoreOption) *Store {
65		if dir == "" {
66			dir = envOr("DDX_BEAD_DIR", ".ddx")
67		}
68		workingDir := dir
69		if filepath.Base(dir) == ".ddx" {
70			workingDir = filepath.Dir(dir)
71		}
72		prefix := envOr("DDX_BEAD_PREFIX", "")
73		if prefix == "" {
74			if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil && cfg.Bead.IDPrefix != "" {
75				prefix = cfg.Bead.IDPrefix
76			}
77		}
78		if prefix == "" {
79			prefix = detectPrefix(workingDir)
80		}
81		backendType := envOr("DDX_BEAD_BACKEND", BackendJSONL)
82	
83		s := &Store{
84			Collection: DefaultCollection,
85			Dir:        dir,
86			Prefix:     prefix,
87			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
88		}
89		for _, opt := range opts {
90			if opt != nil {
91				opt(s)
92			}
93		}
94		spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
95		s.File, s.LockDir = spec.PathsUnder(dir)
96	
97		// Set up external backend if configured. bd/br lack per-collection
98		// scoping in their CLI, so non-default collections (e.g. beads-archive)
99		// route through a JSONL fallback the external backend transparently
100		// delegates to. The default collection always goes straight to bd/br
101		// to preserve the existing interchange contract (schema_compat_test.go,
102		// import/export round-trip).
103		switch backendType {
104		case BackendBD, BackendBR:
105			var fallback Backend
106			if s.Collection != DefaultCollection {
107				fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
108			}
109			if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
110				s.backend = ext
111			}
112			// Fall through to JSONL if tool not available
113		}
114	
115		return s
116	}
117	
118	// NewStoreWithBackend creates a store with an explicit backend (for testing).
119	func NewStoreWithBackend(dir string, b Backend) *Store {
120		s := NewStore(dir)
121		s.backend = b
122		return s
123	}
124	
125	// NewStoreWithCollection creates a store for a named logical collection.
126	func NewStoreWithCollection(dir, collection string) *Store {
127		return NewStore(dir, WithCollection(collection))
128	}
129	
130	// Init creates the storage directory and file.
131	func (s *Store) Init() error {
132		if s.backend != nil {
133			return s.backend.Init()
134		}
135		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
136			return fmt.Errorf("bead: init dir: %w", err)
137		}
138		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
139		if err != nil {
140			return fmt.Errorf("bead: init file: %w", err)
141		}
142		return f.Close()
143	}
144	
145	// GenID generates a unique bead ID with the configured prefix.
146	func (s *Store) GenID() (string, error) {
147		b := make([]byte, 4)
148		if _, err := rand.Read(b); err != nil {
149			return "", fmt.Errorf("bead: gen id: %w", err)
150		}
151		return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
152	}
153	
154	// ReadAll loads all beads from the configured backend.
155	func (s *Store) ReadAll() ([]Bead, error) {
156		return s.ReadAllFiltered(nil)
157	}
158	
159	// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
160	// those for which the predicate returns true. When the predicate is nil every
161	// bead is returned (equivalent to ReadAll). The predicate is applied at the
162	// per-entry parse boundary after fold — matched beads are appended directly to
163	// the return slice without first being held in an intermediate full-corpus
164	// list, so queries that match a small subset avoid materializing the
165	// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
166	func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
167		if s.backend != nil {
168			all, err := s.backend.ReadAll()
169			if err != nil {
170				return nil, err
171			}
172			if pred == nil {
173				return all, nil
174			}
175			out := make([]Bead, 0, len(all))
176			for _, b := range all {
177				if pred(b) {
178					out = append(out, b)
179				}
180			}
181			return out, nil
182		}
183		beads, warnings, err := s.readAllRaw()
184		if err != nil {
185			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
186		}
187		beads = foldLatestBeads(beads)
188		for _, warning := range warnings {
189			fmt.Fprintln(os.Stderr, warning)
190		}
191		if len(warnings) > 0 && len(beads) > 0 {
192			repaired, repairErr := s.repairJSONL()
193			if repairErr != nil {
194				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
195			}
196			if repaired {
197				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
198			}
199		}
200		if len(beads) == 0 && len(warnings) > 0 {
201			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
202		}
203		if pred == nil {
204			return beads, nil
205		}
206		out := make([]Bead, 0, len(beads))
207		for _, b := range beads {
208			if pred(b) {
209				out = append(out, b)
210			}
211		}
212		return out, nil
213	}
214	
215	func (s *Store) readAllRaw() ([]Bead, []string, error) {
216		data, err := os.ReadFile(s.File)
217		if os.IsNotExist(err) {
218			return nil, nil, nil
219		}
220		if err != nil {
221			return nil, nil, fmt.Errorf("read: %w", err)
222		}
223		beads, warnings, err := parseBeadJSONL(data)
224		if err != nil {
225			return nil, nil, err
226		}
227		return beads, warnings, nil
228	}
229	
230	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
231		scanner := bufio.NewScanner(bytes.NewReader(data))
232		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
233		// reviewer stream dumped into events[].body, and bd-exported lines stacking
234		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
235		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
236		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
237	
238		var beads []Bead
239		var warnings []string
240		lineNo := 0
241		for scanner.Scan() {
242			lineNo++
243			line := strings.TrimSpace(scanner.Text())
244			if line == "" {
245				continue
246			}
247			b, err := unmarshalBead([]byte(line))
248			if err != nil {
249				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
250				continue
251			}
252			beads = append(beads, b)
253		}
254		if err := scanner.Err(); err != nil {
255			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
256		}
257		return beads, warnings, nil
258	}
259	
260	func (s *Store) repairJSONL() (bool, error) {
261		var repaired bool
262		err := s.WithLock(func() error {
263			beads, warnings, err := s.readAllRaw()
264			if err != nil {
265				return err
266			}
267			beads = foldLatestBeads(beads)
268			if len(warnings) == 0 || len(beads) == 0 {
269				return nil
270			}
271			backupPath := s.File + ".bak"
272			backupData, err := os.ReadFile(s.File)
273			if err != nil {
274				return fmt.Errorf("read current file: %w", err)
275			}
276			if err := writeAtomicFile(backupPath, backupData); err != nil {
277				return fmt.Errorf("write backup: %w", err)
278			}
279			if err := s.WriteAll(beads); err != nil {
280				return fmt.Errorf("write repaired file: %w", err)
281			}
282			repaired = true
283			return nil
284		})
285		return repaired, err
286	}
287	
288	func foldLatestBeads(beads []Bead) []Bead {
289		if len(beads) == 0 {
290			return nil
291		}
292	
293		latest := make(map[string]Bead, len(beads))
294		lastSeen := make(map[string]int, len(beads))
295		for i, b := range beads {
296			latest[b.ID] = b
297			lastSeen[b.ID] = i
298		}
299	
300		ids := make([]string, 0, len(latest))
301		for id := range latest {
302			ids = append(ids, id)
303		}
304		sort.Slice(ids, func(i, j int) bool {
305			if lastSeen[ids[i]] != lastSeen[ids[j]] {
306				return lastSeen[ids[i]] < lastSeen[ids[j]]
307			}
308			return ids[i] < ids[j]
309		})
310	
311		out := make([]Bead, 0, len(ids))
312		for _, id := range ids {
313			out = append(out, latest[id])
314		}
315		return out
316	}
317	
318	func (s *Store) readAllLatestRaw() ([]Bead, []string, error) {
319		beads, warnings, err := s.readAllRaw()
320		if err != nil {
321			return nil, nil, err
322		}
323		return foldLatestBeads(beads), warnings, nil
324	}
325	
326	// tmpPath returns a unique temp file path in the same directory as path.
327	// Uses pid + 4 random bytes so concurrent processes don't collide.
328	func tmpPath(path string) (string, error) {
329		b := make([]byte, 4)
330		if _, err := rand.Read(b); err != nil {
331			return "", err
332		}
333		return fmt.Sprintf("%s.tmp-%d-%s", path, os.Getpid(), hex.EncodeToString(b)), nil
334	}
335	
336	func writeAtomicFile(path string, data []byte) error {
337		tmp, err := tmpPath(path)
338		if err != nil {
339			return err
340		}
341		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
342		if err != nil {
343			return err
344		}
345		if _, err := f.Write(data); err != nil {
346			f.Close()
347			_ = os.Remove(tmp)
348			return err
349		}
350		if err := f.Sync(); err != nil {
351			f.Close()
352			_ = os.Remove(tmp)
353			return err
354		}
355		if err := f.Close(); err != nil {
356			_ = os.Remove(tmp)
357			return err
358		}
359		if err := os.Rename(tmp, path); err != nil {
360			_ = os.Remove(tmp)
361			return err
362		}
363		return nil
364	}
365	
366	func normalizeCollection(name string) string {
367		name = strings.TrimSpace(name)
368		if name == "" {
369			return DefaultCollection
370		}
371		name = strings.TrimSuffix(name, ".jsonl")
372		return name
373	}
374	
375	// WriteAll writes all beads to the configured backend, sorted by ID.
376	func (s *Store) WriteAll(beads []Bead) error {
377		sort.Slice(beads, func(i, j int) bool {
378			return beads[i].ID < beads[j].ID
379		})
380	
381		if s.backend != nil {
382			return s.backend.WriteAll(beads)
383		}
384	
385		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
386			return fmt.Errorf("bead: mkdir: %w", err)
387		}
388	
389		tmp, err := tmpPath(s.File)
390		if err != nil {
391			return fmt.Errorf("bead: tmp name: %w", err)
392		}
393		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
394		if err != nil {
395			return fmt.Errorf("bead: create tmp: %w", err)
396		}
397	
398		enc := json.NewEncoder(f)
399		enc.SetEscapeHTML(false)
400		for _, b := range beads {
401			data, err := marshalBead(b)
402			if err != nil {
403				f.Close()
404				os.Remove(tmp)
405				return fmt.Errorf("bead: marshal: %w", err)
406			}
407			if _, err := f.Write(data); err != nil {
408				f.Close()
409				os.Remove(tmp)
410				return fmt.Errorf("bead: write: %w", err)
411			}
412			if _, err := f.WriteString("\n"); err != nil {
413				f.Close()
414				os.Remove(tmp)
415				return fmt.Errorf("bead: write newline: %w", err)
416			}
417		}
418	
419		if err := f.Sync(); err != nil {
420			f.Close()
421			os.Remove(tmp)
422			return fmt.Errorf("bead: sync tmp: %w", err)
423		}
424		if err := f.Close(); err != nil {
425			os.Remove(tmp)
426			return fmt.Errorf("bead: close tmp: %w", err)
427		}
428		if err := os.Rename(tmp, s.File); err != nil {
429			os.Remove(tmp)
430			return fmt.Errorf("bead: rename tmp: %w", err)
431		}
432		return nil
433	}
434	
435	// Create adds a new bead. Assigns defaults, validates, then persists.
436	func (s *Store) Create(b *Bead) error {
437		now := time.Now().UTC()
438		if b.ID == "" {
439			id, err := s.GenID()
440			if err != nil {
441				return err
442			}
443			b.ID = id
444		}
445		if b.IssueType == "" {
446			b.IssueType = DefaultType
447		}
448		if b.Status == "" {
449			b.Status = DefaultStatus
450		}
451		b.CreatedAt = now
452		b.UpdatedAt = now
453	
454		// Validate after defaults are applied so hooks see final state
455		if err := s.validateBead(b); err != nil {
456			return err
457		}
458		// Run create hook
459		if err := s.runHook("validate-bead-create", b); err != nil {
460			return err
461		}
462	
463		return s.WithLock(func() error {
464			beads, _, err := s.readAllLatestRaw()
465			if err != nil {
466				return err
467			}
468			// Reject duplicate IDs
469			for _, e := range beads {
470				if e.ID == b.ID {
471					return fmt.Errorf("bead: duplicate id: %s", b.ID)
472				}
473			}
474			// Validate deps reference existing beads
475			depIDs := b.DepIDs()
476			if len(depIDs) > 0 {
477				existing := make(map[string]bool)
478				for _, e := range beads {
479					existing[e.ID] = true
480				}
481				for _, dep := range depIDs {
482					if !existing[dep] {
483						return fmt.Errorf("bead: dependency not found: %s", dep)
484					}
485				}
486			}
487			beads = append(beads, *b)
488			return s.WriteAll(beads)
489		})
490	}
491	
492	// Get retrieves a bead by ID.
493	func (s *Store) Get(id string) (*Bead, error) {
494		beads, err := s.ReadAll()
495		if err != nil {
496			return nil, err
497		}
498		for _, b := range beads {
499			if b.ID == id {
500				return &b, nil
501			}
502		}
503		return nil, fmt.Errorf("bead: not found: %s", id)
504	}
505	
506	// Update modifies a bead by ID. The mutate function receives a pointer to modify.
507	func (s *Store) Update(id string, mutate func(*Bead)) error {
508		return s.WithLock(func() error {
509			beads, _, err := s.readAllLatestRaw()
510			if err != nil {
511				return err
512			}
513			found := false
514			for i := range beads {
515				if beads[i].ID == id {
516					mutate(&beads[i])
517					beads[i].UpdatedAt = time.Now().UTC()
518					// Core validation after mutation
519					if err := s.validateBead(&beads[i]); err != nil {
520						return err
521					}
522					// Run update hook
523					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
524						return err
525					}
526					found = true
527					break
528				}
529			}
530			if !found {
531				return fmt.Errorf("bead: not found: %s", id)
532			}
533			return s.WriteAll(beads)
534		})
535	}
536	
537	// HeartbeatInterval is how often a claim owner should refresh
538	// execute-loop-heartbeat-at while running. Exposed as a variable so tests
539	// can override it.
540	var HeartbeatInterval = 30 * time.Second
541	
542	// HeartbeatTTL is the maximum allowed age of execute-loop-heartbeat-at
543	// before another worker may reclaim the bead. Defaults to 3× HeartbeatInterval.
544	// Exposed as a variable so tests can override it.
545	var HeartbeatTTL = 90 * time.Second
546	
547	// Claim sets a bead to in_progress with claim metadata.
548	// Fails if the bead is already claimed (status == in_progress) with a
549	// fresh heartbeat. A bead whose execute-loop-heartbeat-at is older than
550	// HeartbeatTTL is considered stalled and will be reclaimed atomically.
551	func (s *Store) Claim(id, assignee string) error {
552		return s.ClaimWithOptions(id, assignee, "", "")
553	}
554	
555	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
556	// session and worktree are optional; machine is derived from os.Hostname().
557	// A stalled in_progress bead (heartbeat older than HeartbeatTTL) is reclaimed
558	// atomically under the store's lock.
559	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
560		machine, _ := os.Hostname()
561		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
562			machine = envID
563		}
564		return s.WithLock(func() error {
565			beads, _, err := s.readAllLatestRaw()
566			if err != nil {
567				return err
568			}
569			for i := range beads {
570				if beads[i].ID != id {
571					continue
572				}
573				switch beads[i].Status {
574				case StatusOpen:
575					// normal claim path
576				case StatusInProgress:
577					if !heartbeatIsStale(beads[i].Extra) {
578						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
579					}
580					// stalled claim — reclaim atomically below
581				default:
582					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
583				}
584				// Refuse claims on beads parked with last_status=push_failed:
585				// the previous attempt landed locally but `git push` was rejected,
586				// so the local commit history exists only on this machine. Re-running
587				// primary work would duplicate or strand commits. The operator must
588				// clear execute-loop-last-status (e.g. by manually pushing or
589				// resetting) before another attempt is allowed.
590				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
591					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
592					if detail != "" {
593						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
594					}
595					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
596				}
597				if beads[i].Extra == nil {
598					beads[i].Extra = make(map[string]any)
599				}
600				now := time.Now().UTC()
601				beads[i].Status = StatusInProgress
602				beads[i].Owner = assignee
603				beads[i].UpdatedAt = now
604				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
605				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
606				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
607				if machine != "" {
608					beads[i].Extra["claimed-machine"] = machine
609				}
610				if session != "" {
611					beads[i].Extra["claimed-session"] = session
612				}
613				if worktree != "" {
614					beads[i].Extra["claimed-worktree"] = worktree
615				}
616				if err := s.validateBead(&beads[i]); err != nil {
617					return err
618				}
619				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
620					return err
621				}
622				return s.WriteAll(beads)
623			}
624			return fmt.Errorf("bead: not found: %s", id)
625		})
626	}
