628	// Heartbeat refreshes execute-loop-heartbeat-at on a claimed bead. Returns
629	// an error if the bead is no longer in_progress (e.g., reclaimed by another
630	// worker), allowing the caller to stop its heartbeat loop.
631	func (s *Store) Heartbeat(id string) error {
632		return s.WithLock(func() error {
633			beads, _, err := s.readAllLatestRaw()
634			if err != nil {
635				return err
636			}
637			for i := range beads {
638				if beads[i].ID != id {
639					continue
640				}
641				if beads[i].Status != StatusInProgress {
642					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, beads[i].Status)
643				}
644				if beads[i].Extra == nil {
645					beads[i].Extra = make(map[string]any)
646				}
647				beads[i].Extra["execute-loop-heartbeat-at"] = time.Now().UTC().Format(time.RFC3339Nano)
648				beads[i].UpdatedAt = time.Now().UTC()
649				return s.WriteAll(beads)
650			}
651			return fmt.Errorf("bead: not found: %s", id)
652		})
653	}
