655	// heartbeatIsStale returns true if the given bead's Extra map has no
656	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
657	func heartbeatIsStale(extra map[string]any) bool {
658		if extra == nil {
659			return true
660		}
661		raw, ok := extra["execute-loop-heartbeat-at"]
662		if !ok {
663			return true
664		}
665		s, ok := raw.(string)
666		if !ok || s == "" {
667			return true
668		}
669		t, err := time.Parse(time.RFC3339Nano, s)
670		if err != nil {
671			// Fall back to RFC3339 for compatibility with legacy entries written
672			// before sub-second resolution. RFC3339Nano is the current canonical
673			// format used by both ClaimWithOptions and Heartbeat write sites.
674			t, err = time.Parse(time.RFC3339, s)
675			if err != nil {
676				return true
677			}
678		}
679		return time.Since(t) > HeartbeatTTL
680	}
