716	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
717	// and returns the new count. Used by the execute-bead worker to detect when a
718	// bead should be auto-closed after repeated no-change attempts.
719	func (s *Store) IncrNoChangesCount(id string) (int, error) {
720		var newCount int
721		err := s.Update(id, func(b *Bead) {
722			if b.Extra == nil {
723				b.Extra = make(map[string]any)
724			}
725			var count int
726			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
727				switch n := v.(type) {
728				case int:
729					count = n
730				case float64:
731					count = int(n)
732				case int64:
733					count = int(n)
734				}
735			}
736			count++
737			b.Extra["execute-loop-no-changes-count"] = count
738			newCount = count
739		})
740		return newCount, err
