743	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
744	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
745	// DDx-authored beads always round-trip through `bd import`. Empirically
746	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
747	const MaxFieldBytes = 65535
748	
749	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
750	// need to preserve the full payload should persist it to a sidecar artifact
751	// and store a path reference in the field; this function is the defense-in-
752	// depth cap for code paths that don't. Returns the input unchanged when it
753	// fits; otherwise returns head+tail truncation with a byte-count marker.
754	func capFieldBytes(s string) string {
755		if len(s) <= MaxFieldBytes {
756			return s
757		}
758		// Reserve a marker that always fits; keep head heavy (2/3) so
759		// human-readable context is preserved for the common short-rationale case.
760		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
761		budget := MaxFieldBytes - len(marker)
762		if budget <= 0 {
763			return s[:MaxFieldBytes]
764		}
765		head := (budget * 2) / 3
766		tail := budget - head
767		return s[:head] + marker + s[len(s)-tail:]
768	}
