770	func (s *Store) AppendEvent(id string, event BeadEvent) error {
771		if event.CreatedAt.IsZero() {
772			event.CreatedAt = time.Now().UTC()
773		}
774		// Defense in depth: cap every event body regardless of caller. The
775		// reviewer write path separately persists the full stream to an artifact
776		// and emits a <=512-byte body; this cap catches anything else.
777		event.Body = capFieldBytes(event.Body)
778		event.Summary = capFieldBytes(event.Summary)
779		// Two storage shapes are possible here: inline Extra["events"] for active
780		// beads, and a sidecar attachment for closed/archived beads (ADR-004
781		// attachment model). When the bead has been externalized we append to the
782		// sidecar and leave the row untouched aside from updated_at.
783		var appendedToAttachment bool
784		if err := s.Update(id, func(b *Bead) {
785			if b.Extra == nil {
786				b.Extra = make(map[string]any)
787			}
788			if hasEventsAttachment(b) {
789				appendedToAttachment = true
790				return
791			}
792			var events []BeadEvent
793			if raw, ok := b.Extra["events"]; ok {
794				events = decodeBeadEvents(raw)
795			}
796			events = append(events, event)
797			b.Extra["events"] = encodeEventsForExtra(events)
798		}); err != nil {
799			return err
800		}
801		if !appendedToAttachment {
802			return nil
803		}
804		// Append to the sidecar under the store lock so concurrent readers and
805		// writers see a consistent events log.
806		return s.WithLock(func() error {
807			existing, err := s.readEventsAttachment(id)
808			if err != nil {
809				return err
810			}
811			existing = append(existing, event)
812			return s.writeEventsAttachment(id, existing)
813		})
814	}
