816	// Events returns the bead's evidence history in insertion order. Reads are
817	// transparent across storage shapes: inline Extra["events"] for active beads,
818	// or the externalized sidecar referenced by Extra[events_attachment] once the
819	// bead has been closed.
820	func (s *Store) Events(id string) ([]BeadEvent, error) {
821		b, err := s.Get(id)
822		if err != nil {
823			return nil, err
824		}
825		events, err := s.eventsForBead(b)
826		if err != nil {
827			return nil, err
828		}
829		if len(events) == 0 {
830			return []BeadEvent{}, nil
831		}
832		out := make([]BeadEvent, len(events))
833		copy(out, events)
834		return out, nil
835	}
