837	// EventsByKind returns all events for a bead filtered by kind, in insertion order.
838	func (s *Store) EventsByKind(id, kind string) ([]BeadEvent, error) {
839		all, err := s.Events(id)
840		if err != nil {
841			return nil, err
842		}
843		out := make([]BeadEvent, 0, len(all))
844		for _, e := range all {
845			if e.Kind == kind {
846				out = append(out, e)
847			}
848		}
849		return out, nil
850	}
