852	func decodeBeadEvents(raw any) []BeadEvent {
853		switch v := raw.(type) {
854		case []BeadEvent:
855			out := make([]BeadEvent, len(v))
856			copy(out, v)
857			return out
858		case []any:
859			out := make([]BeadEvent, 0, len(v))
860			for _, item := range v {
861				m, ok := item.(map[string]any)
862				if !ok {
863					continue
864				}
865				out = append(out, beadEventFromMap(m))
866			}
867			return out
868		case []map[string]any:
869			out := make([]BeadEvent, 0, len(v))
870			for _, item := range v {
871				out = append(out, beadEventFromMap(item))
872			}
873			return out
874		default:
875			return nil
876		}
877	}
878	
879	func beadEventFromMap(m map[string]any) BeadEvent {
880		e := BeadEvent{}
881		if v, ok := m["kind"].(string); ok {
882			e.Kind = v
883		}
884		if v, ok := m["summary"].(string); ok {
885			e.Summary = v
886		}
887		if v, ok := m["body"].(string); ok {
888			e.Body = v
889		}
890		if v, ok := m["actor"].(string); ok {
891			e.Actor = v
892		}
893		if v, ok := m["source"].(string); ok {
894			e.Source = v
895		}
896		if v, ok := m["created_at"].(string); ok {
897			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
898				e.CreatedAt = parsed
899			}
900		}
901		return e
902	}
