904	// Close sets a bead's status to closed. When the close succeeds and the bead
905	// carries an inline event history, those events are moved to a sidecar
906	// attachment under .ddx/attachments/<id>/events.jsonl so the active row stays
907	// small (per ADR-004's attachment model and TD-027 §c).
908	func (s *Store) Close(id string) error {
909		if err := s.Update(id, func(b *Bead) {
910			b.Status = StatusClosed
911		}); err != nil {
912			return err
913		}
914		if err := s.externalizeEvents(id); err != nil {
915			return err
916		}
917		s.maybeOpportunisticArchive()
918		return nil
919	}
