921	// externalizeEvents moves a bead's inline events into its sidecar attachment
922	// under a fresh lock. Safe to call repeatedly — no-op when there are no
923	// inline events (already externalized, or none recorded).
924	func (s *Store) externalizeEvents(id string) error {
925		return s.WithLock(func() error {
926			beads, _, err := s.readAllLatestRaw()
927			if err != nil {
928				return err
929			}
930			for i := range beads {
931				if beads[i].ID != id {
932					continue
933				}
934				if err := s.externalizeEventsInPlace(&beads[i]); err != nil {
935					return err
936				}
937				return s.WriteAll(beads)
938			}
939			return nil
940		})
941	}
