943	// ErrClosureGateRejected indicates a close was refused because the bead does
944	// not carry the evidence required for an automated closure: a terminal
945	// verdict event (review APPROVE with non-empty rationale, or an explicit
946	// review-skipped / manual-close marker) AND an execution-evidence marker
947	// (closing_commit_sha, session_id, or an execute-bead success event in the
948	// events history).
949	//
950	// Automated execute-loop paths (execute-bead + reviewer) always go through
951	// CloseWithEvidence. The plain Store.Close remains as the manual
952	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
953	// acceptance §1).
954	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
955	
956	// ClosureGate inspects a bead and returns nil iff the close is safe. It
957	// rejects only the specific shapes that caused the 2026-04-18/20
958	// review-malfunction incidents:
959	//
960	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
961	//     closing_commit_sha. Rejected by the execution-evidence check —
962	//     closing_commit_sha must be non-empty OR at least one event must exist.
963	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
964	//     body is empty. Rejected — APPROVE with no rationale is exactly the
965	//     parse-mis-extract shape the reviewer bug produced.
966	//
967	// Beads without a review step (--no-review, no Reviewer configured, already-
968	// satisfied paths) pass the gate as long as they carry execution evidence.
969	// This keeps the surface small: the gate catches known-bad shapes, not every
970	// conceivable edge case. Additional invariants belong in future dedicated
971	// beads so the rejection reason stays auditable.
972	func ClosureGate(b *Bead) error {
973		if b == nil {
974			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
975		}
976		hasClosingCommit := false
977		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
978			hasClosingCommit = true
979		}
980		events := decodeBeadEvents(b.Extra["events"])
981		// Externalized events still count as evidence for the gate. We only need
982		// to know whether *some* event history exists, not iterate it; the
983		// gate's APPROVE-with-empty-rationale check below relies on inline events
984		// (the verdict is recorded before externalization).
985		hasAttachedEvents := hasEventsAttachment(b)
986		// Reject the axon-c5cc071a shape: no events AND no closing commit.
987		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
988			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
989		}
990		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
991		for _, e := range events {
992			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
993				if strings.TrimSpace(e.Body) == "" {
994					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
995				}
996			}
997		}
998		return nil
999	}
