1001	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1002	// sessionID is the agent session that completed the work.
1003	// commitSHA is the exact closing commit SHA when it is known.
1004	//
1005	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1006	// via this path without a terminal verdict event plus execution evidence.
1007	// Store.Close is the manual-administration escape hatch when the gate is
1008	// inappropriate.
1009	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1010		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1011			return err
1012		}
1013		// Externalize events only when the gate actually transitioned the bead
1014		// to closed; rejected closes leave the bead open and inline.
1015		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1016			if err := s.externalizeEvents(id); err != nil {
1017				return err
1018			}
1019		}
1020		s.maybeOpportunisticArchive()
1021		return nil
1022	}
