1024	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1025		return s.Update(id, func(b *Bead) {
1026			if b.Extra == nil {
1027				b.Extra = make(map[string]any)
1028			}
1029			if sessionID != "" {
1030				b.Extra["session_id"] = sessionID
1031			}
1032			if commitSHA != "" {
1033				b.Extra["closing_commit_sha"] = commitSHA
1034			}
1035			if err := ClosureGate(b); err != nil {
1036				// Surface via bead notes so a later operator audit can see why the
1037				// close was refused; a single error path would be dropped by the
1038				// Update callback signature (no error return).
1039				appendClosureRejectNote(b, err)
1040				return
1041			}
1042			b.Status = StatusClosed
1043		})
1044	}
