1046	func appendClosureRejectNote(b *Bead, err error) {
1047		stamp := time.Now().UTC().Format(time.RFC3339)
1048		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1049		if b.Notes == "" {
1050			b.Notes = note
1051			return
1052		}
1053		b.Notes = b.Notes + "\n" + note
1054	}
