1056	// AppendNotes appends operator-facing notes to an existing bead.
1057	func (s *Store) AppendNotes(id string, appendNotes string) error {
1058		appendNotes = strings.TrimSpace(appendNotes)
1059		if appendNotes == "" {
1060			return nil
1061		}
1062		return s.Update(id, func(b *Bead) {
1063			if b.Notes != "" {
1064				b.Notes = b.Notes + "\n\n" + appendNotes
1065				return
1066			}
1067			b.Notes = appendNotes
1068		})
1069	}
