1071	// Reopen sets a bead's status back to open, clears claim fields, optionally
1072	// appends notes, and records an immutable reopen event — all in one atomic
1073	// lock acquisition.
1074	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1075		now := time.Now().UTC()
1076		return s.WithLock(func() error {
1077			beads, _, err := s.readAllLatestRaw()
1078			if err != nil {
1079				return err
1080			}
1081			found := false
1082			for i := range beads {
1083				if beads[i].ID != id {
1084					continue
1085				}
1086				b := &beads[i]
1087				b.Status = StatusOpen
1088				b.Owner = ""
1089				b.UpdatedAt = now
1090				if b.Extra == nil {
1091					b.Extra = make(map[string]any)
1092				}
1093				// Clear claim fields
1094				delete(b.Extra, "claimed-at")
1095				delete(b.Extra, "claimed-pid")
1096				delete(b.Extra, "claimed-machine")
1097				delete(b.Extra, "claimed-session")
1098				delete(b.Extra, "claimed-worktree")
1099				delete(b.Extra, "execute-loop-heartbeat-at")
1100				// Append notes
1101				if appendNotes != "" {
1102					if b.Notes != "" {
1103						b.Notes = b.Notes + "\n\n" + appendNotes
1104					} else {
1105						b.Notes = appendNotes
1106					}
1107				}
1108				// Record reopen event. If events were externalized at close,
1109				// pull them back inline so the active row carries the full
1110				// history again and the attachment ref is dropped.
1111				if hasEventsAttachment(b) {
1112					if err := s.inlineEventsInPlace(b); err != nil {
1113						return err
1114					}
1115					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1116				}
1117				var events []BeadEvent
1118				if raw, ok := b.Extra["events"]; ok {
1119					events = decodeBeadEvents(raw)
1120				}
1121				evt := BeadEvent{
1122					Kind:      "reopen",
1123					CreatedAt: now,
1124				}
1125				if reason != "" {
1126					evt.Summary = reason
1127				}
1128				events = append(events, evt)
1129				encoded := make([]map[string]any, 0, len(events))
1130				for _, e := range events {
1131					encoded = append(encoded, map[string]any{
1132						"kind":       e.Kind,
1133						"summary":    e.Summary,
1134						"body":       e.Body,
1135						"actor":      e.Actor,
1136						"created_at": e.CreatedAt,
1137						"source":     e.Source,
1138					})
1139				}
1140				b.Extra["events"] = encoded
1141				if err := s.validateBead(b); err != nil {
1142					return err
1143				}
1144				if err := s.runHook("validate-bead-update", b); err != nil {
1145					return err
1146				}
1147				found = true
1148				break
1149			}
1150			if !found {
1151				return fmt.Errorf("bead: not found: %s", id)
1152			}
1153			return s.WriteAll(beads)
1154		})
1155	}
