1190	// matchesWhere returns true if the bead satisfies all key=value predicates.
1191	// It checks known struct fields first, then falls back to Extra.
1192	func matchesWhere(b Bead, where map[string]string) bool {
1193		for k, v := range where {
1194			var actual string
1195			switch k {
1196			case "id":
1197				actual = b.ID
1198			case "title":
1199				actual = b.Title
1200			case "status":
1201				actual = b.Status
1202			case "issue_type":
1203				actual = b.IssueType
1204			case "owner":
1205				actual = b.Owner
1206			case "assignee":
1207				actual = b.Owner
1208			case "parent":
1209				actual = b.Parent
1210			case "description":
1211				actual = b.Description
1212			case "acceptance":
1213				actual = b.Acceptance
1214			case "notes":
1215				actual = b.Notes
1216			default:
1217				// Fall back to Extra map for unknown/workflow-specific fields
1218				if b.Extra != nil {
1219					if ev, ok := b.Extra[k]; ok {
1220						actual = fmt.Sprintf("%v", ev)
1221					}
1222				}
1223			}
1224			if actual != v {
1225				return false
1226			}
1227		}
1228		return true
1229	}
