1243	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1244	// they are NOT execution-eligible: epic containers, retry cooldown,
1245	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1246	// emits when the execution queue is empty but `ddx bead ready` is not.
1247	type ReadyExecutionBreakdown struct {
1248		SkippedEpics       []string
1249		SkippedOnCooldown  []string
1250		SkippedNotEligible []string
1251		SkippedSuperseded  []string
1252		NextRetryAfter     string
1253	}
1254	
1255	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1256		out := ReadyExecutionBreakdown{}
1257		ready, err := s.Ready()
1258		if err != nil {
1259			return out, err
1260		}
1261		now := time.Now().UTC()
1262		var soonestRetry time.Time
1263		for _, b := range ready {
1264			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1265				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1266					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1267						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1268						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1269							soonestRetry = retryAfter
1270						}
1271						continue
1272					}
1273				}
1274			}
1275			if eligible, ok := b.Extra["execution-eligible"]; ok {
1276				if val, isBool := eligible.(bool); isBool && !val {
1277					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1278					continue
1279				}
1280			}
1281			if sup, ok := b.Extra["superseded-by"]; ok {
1282				if s, isStr := sup.(string); isStr && s != "" {
1283					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1284					continue
1285				}
1286			}
1287		}
1288		if !soonestRetry.IsZero() {
1289			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1290		}
1291		return out, nil
1292	}
