1294	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1295		beads, err := s.ReadAll()
1296		if err != nil {
1297			return nil, err
1298		}
1299		statusMap := make(map[string]string)
1300		for _, b := range beads {
1301			statusMap[b.ID] = b.Status
1302		}
1303	
1304		var ready []Bead
1305		for _, b := range beads {
1306			if b.Status != StatusOpen {
1307				// Surface stalled in_progress beads so a fresh worker can
1308				// reclaim them atomically in Claim().
1309				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1310					// fall through to dependency check below
1311				} else {
1312					continue
1313				}
1314			}
1315			allSatisfied := true
1316			for _, depID := range b.DepIDs() {
1317				if statusMap[depID] != StatusClosed {
1318					allSatisfied = false
1319					break
1320				}
1321			}
1322			if !allSatisfied {
1323				continue
1324			}
1325			if executionOnly {
1326				// Filter by execution-eligible (default true if absent)
1327				eligible, ok := b.Extra["execution-eligible"]
1328				if ok {
1329					if val, isBool := eligible.(bool); isBool && !val {
1330						continue
1331					}
1332				}
1333				// Filter out superseded beads
1334				if sup, ok := b.Extra["superseded-by"]; ok {
1335					if s, isStr := sup.(string); isStr && s != "" {
1336						continue
1337					}
1338				}
1339				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1340					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1341						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1342							continue
1343						}
1344					}
1345				}
1346			}
1347			ready = append(ready, b)
1348		}
1349	
1350		sortBeadsForQueue(ready)
1351	
1352		return ready, nil
1353	}
