1355	// Blocked returns open beads with at least one unclosed dependency.
1356	func (s *Store) Blocked() ([]Bead, error) {
1357		beads, err := s.ReadAll()
1358		if err != nil {
1359			return nil, err
1360		}
1361		statusMap := make(map[string]string)
1362		for _, b := range beads {
1363			statusMap[b.ID] = b.Status
1364		}
1365	
1366		var blocked []Bead
1367		for _, b := range beads {
1368			if b.Status != StatusOpen {
1369				continue
1370			}
1371			for _, depID := range b.DepIDs() {
1372				if statusMap[depID] != StatusClosed {
1373					blocked = append(blocked, b)
1374					break
1375				}
1376			}
1377		}
1378		sortBeadsForQueue(blocked)
1379		return blocked, nil
1380	}
1381	
1382	// BlockedAll returns open beads that are currently not runnable, classified
1383	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1384	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1385	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1386	// that is both dep-blocked and cooldown-parked is reported as dependency-
1387	// blocked, because deps are the stronger blocker.
1388	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1389		beads, err := s.ReadAll()
1390		if err != nil {
1391			return nil, err
1392		}
1393		statusMap := make(map[string]string)
1394		for _, b := range beads {
1395			statusMap[b.ID] = b.Status
1396		}
1397	
1398		now := time.Now().UTC()
1399		var entries []BlockedBead
1400		for _, b := range beads {
1401			if b.Status != StatusOpen {
1402				continue
1403			}
1404	
1405			var unclosed []string
1406			for _, depID := range b.DepIDs() {
1407				if statusMap[depID] != StatusClosed {
1408					unclosed = append(unclosed, depID)
1409				}
1410			}
1411			if len(unclosed) > 0 {
1412				entries = append(entries, BlockedBead{
1413					Bead: b,
1414					Blocker: Blocker{
1415						Kind:           BlockerKindDependency,
1416						UnclosedDepIDs: unclosed,
1417					},
1418				})
1419				continue
1420			}
1421	
1422			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1423			if !ok {
1424				continue
1425			}
1426			retryAfterStr, isStr := retryAfterRaw.(string)
1427			if !isStr || retryAfterStr == "" {
1428				continue
1429			}
1430			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1431			if err != nil || !retryAfter.After(now) {
1432				continue
1433			}
1434			blocker := Blocker{
1435				Kind:           BlockerKindRetryCooldown,
1436				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1437			}
1438			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1439				if s, ok := v.(string); ok {
1440					blocker.LastStatus = s
1441				}
1442			}
1443			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1444				if s, ok := v.(string); ok {
1445					blocker.LastDetail = s
1446				}
1447			}
1448			entries = append(entries, BlockedBead{
1449				Bead:    b,
1450				Blocker: blocker,
1451			})
1452		}
1453	
1454		sort.SliceStable(entries, func(i, j int) bool {
1455			if entries[i].Priority != entries[j].Priority {
1456				return entries[i].Priority < entries[j].Priority
1457			}
1458			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1459				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1460			}
1461			return entries[i].ID < entries[j].ID
1462		})
1463		return entries, nil
1464	}
1465	
1466	func sortBeadsForQueue(beads []Bead) {
1467		sort.SliceStable(beads, func(i, j int) bool {
1468			if beads[i].Priority != beads[j].Priority {
1469				return beads[i].Priority < beads[j].Priority
1470			}
1471			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1472				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1473			}
1474			return beads[i].ID < beads[j].ID
1475		})
1476	}
