1478	// Status returns aggregate counts.
1479	func (s *Store) Status() (*StatusCounts, error) {
1480		beads, err := s.ReadAll()
1481		if err != nil {
1482			return nil, err
1483		}
1484		ready, err := s.Ready()
1485		if err != nil {
1486			return nil, err
1487		}
1488		blocked, err := s.Blocked()
1489		if err != nil {
1490			return nil, err
1491		}
1492	
1493		// Pull in archive partner so totals survive `bead migrate` — the archive
1494		// only carries closed beads, so Ready/Blocked aren't affected.
1495		seen := make(map[string]bool, len(beads))
1496		all := make([]Bead, 0, len(beads))
1497		for _, b := range beads {
1498			if seen[b.ID] {
1499				continue
1500			}
1501			seen[b.ID] = true
1502			all = append(all, b)
1503		}
1504		if s.Collection == DefaultCollection {
1505			archive := s.archivePartner()
1506			if archived, aerr := archive.ReadAll(); aerr == nil {
1507				for _, b := range archived {
1508					if seen[b.ID] {
1509						continue
1510					}
1511					seen[b.ID] = true
1512					all = append(all, b)
1513				}
1514			}
1515		}
1516	
1517		counts := &StatusCounts{Total: len(all), Ready: len(ready), Blocked: len(blocked)}
1518		for _, b := range all {
1519			switch b.Status {
1520			case StatusOpen:
1521				counts.Open++
1522			case StatusClosed:
1523				counts.Closed++
1524			}
1525		}
1526		return counts, nil
1527	}
