1529	// DepAdd adds a dependency: id depends on depID.
1530	func (s *Store) DepAdd(id, depID string) error {
1531		return s.WithLock(func() error {
1532			beads, _, err := s.readAllLatestRaw()
1533			if err != nil {
1534				return err
1535			}
1536			var target *Bead
1537			depExists := false
1538			for i := range beads {
1539				if beads[i].ID == id {
1540					target = &beads[i]
1541				}
1542				if beads[i].ID == depID {
1543					depExists = true
1544				}
1545			}
1546			if target == nil {
1547				return fmt.Errorf("bead: not found: %s", id)
1548			}
1549			if !depExists {
1550				return fmt.Errorf("bead: dependency not found: %s", depID)
1551			}
1552			if id == depID {
1553				return fmt.Errorf("bead: cannot depend on self")
1554			}
1555			if target.HasDep(depID) {
1556				return nil // already exists
1557			}
1558	
1559			// Check for circular dependency
1560			depMap := make(map[string][]string)
1561			for _, b := range beads {
1562				depMap[b.ID] = b.DepIDs()
1563			}
1564			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1565			if hasCycle(depMap, id) {
1566				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1567			}
1568	
1569			target.AddDep(depID, "blocks")
1570			target.UpdatedAt = time.Now().UTC()
1571			return s.WriteAll(beads)
1572		})
1573	}
