1582	// DepTree returns a text representation of the dependency tree.
1583	func (s *Store) DepTree(rootID string) (string, error) {
1584		beads, err := s.ReadAll()
1585		if err != nil {
1586			return "", err
1587		}
1588		// Pull in archive partner so the tree survives `bead migrate` — closed
1589		// beads stored only in the archive must still appear.
1590		if s.Collection == DefaultCollection {
1591			archive := s.archivePartner()
1592			if archived, aerr := archive.ReadAll(); aerr == nil {
1593				seen := make(map[string]bool, len(beads))
1594				for _, b := range beads {
1595					seen[b.ID] = true
1596				}
1597				for _, b := range archived {
1598					if seen[b.ID] {
1599						continue
1600					}
1601					beads = append(beads, b)
1602				}
1603			}
1604		}
1605		byID := make(map[string]*Bead)
1606		for i := range beads {
1607			byID[beads[i].ID] = &beads[i]
1608		}
1609	
1610		if rootID != "" {
1611			target, ok := byID[rootID]
1612			if !ok {
1613				return "", fmt.Errorf("bead: not found: %s", rootID)
1614			}
1615			var sb strings.Builder
1616			// Walk up: show the dependency chain (what this node depends on)
1617			depChain := s.depChainUp(byID, rootID)
1618			if len(depChain) > 0 {
1619				// Print deps as the tree root(s), with the target as their child
1620				for _, depID := range depChain {
1621					if dep, ok := byID[depID]; ok {
1622						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1623					}
1624				}
1625			}
1626			// Print the target node
1627			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1628			// Print dependents (what depends on this node)
1629			var children []string
1630			for _, other := range sortedKeys(byID) {
1631				if byID[other].HasDep(rootID) {
1632					children = append(children, other)
1633				}
1634			}
1635			for _, child := range children {
1636				s.printTree(&sb, byID, child, "  ", true)
1637			}
1638			return sb.String(), nil
1639		}
1640	
1641		// Find roots (beads that have no dependencies themselves)
1642		var roots []string
1643		for _, b := range beads {
1644			if len(b.Dependencies) == 0 {
1645				roots = append(roots, b.ID)
1646			}
1647		}
1648		sort.Strings(roots)
1649	
1650		var sb strings.Builder
1651		for i, root := range roots {
1652			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1653		}
1654		return sb.String(), nil
1655	}
1656	
1657	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1658		b, ok := byID[id]
1659		if !ok {
1660			return
1661		}
1662	
1663		connector := "├── "
1664		if last {
1665			connector = "└── "
1666		}
1667		if prefix == "" {
1668			connector = ""
1669		}
1670	
1671		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1672	
1673		// Find beads that depend on this one (children in the tree)
1674		var children []string
1675		for _, other := range sortedKeys(byID) {
1676			if byID[other].HasDep(id) {
1677				children = append(children, other)
1678			}
1679		}
1680	
1681		childPrefix := prefix
1682		if prefix != "" {
1683			if last {
1684				childPrefix += "    "
1685			} else {
1686				childPrefix += "│   "
1687			}
1688		}
1689	
1690		for i, child := range children {
1691			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1692		}
1693	}
1694	
1695	// depChainUp returns the direct dependencies of a bead (upstream IDs).
1696	func (s *Store) depChainUp(byID map[string]*Bead, id string) []string {
1697		b, ok := byID[id]
1698		if !ok {
1699			return nil
1700		}
1701		return b.DepIDs()
1702	}
