1704	// validateBead checks core invariants that must hold for any bead (create or update).
1705	func (s *Store) validateBead(b *Bead) error {
1706		if strings.TrimSpace(b.Title) == "" {
1707			return fmt.Errorf("bead: title is required")
1708		}
1709		if b.Priority < MinPriority || b.Priority > MaxPriority {
1710			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1711		}
1712		if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed && b.Status != StatusBlocked {
1713			return fmt.Errorf("bead: invalid status: %s", b.Status)
1714		}
1715		// Self-ref check
1716		for _, depID := range b.DepIDs() {
1717			if depID == b.ID && b.ID != "" {
1718				return fmt.Errorf("bead: cannot depend on self")
1719			}
1720		}
1721		return nil
1722	}
1723	
1724	// detectPrefix derives the bead ID prefix from the repository/directory name,
1725	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1726	// workingDir is the project root to use for git commands; when empty the
1727	// process working directory is used (legacy behaviour, prone to worktree
1728	// path contamination). Falls back to DefaultPrefix if detection fails.
1729	func detectPrefix(workingDir string) string {
1730		// Try git repo root name first, running from the known project root so
1731		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
1732		// contaminate the prefix with their ephemeral directory names.
1733		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
1734		if out, err := cmd.Output(); err == nil {
1735			root := strings.TrimSpace(string(out))
1736			if root != "" {
1737				return filepath.Base(root)
1738			}
1739		}
1740		// Fall back to the provided working dir, then cwd.
1741		if workingDir != "" {
1742			return filepath.Base(workingDir)
1743		}
1744		if wd, err := os.Getwd(); err == nil {
1745			return filepath.Base(wd)
1746		}
1747		return DefaultPrefix
1748	}
1749	
1750	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1751		v := os.Getenv(envKey)
1752		if v == "" {
1753			return fallback
1754		}
1755		// Try as seconds (plain number)
1756		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1757			return time.Duration(secs * float64(time.Second))
1758		}
1759		// Try as Go duration
1760		if d, err := time.ParseDuration(v); err == nil {
1761			return d
1762		}
1763		return fallback
1764	}
1765	
1766	func envOr(key, fallback string) string {
1767		if v := os.Getenv(key); v != "" {
1768			return v
1769		}
1770		return fallback
1771	}
